<template><view class="page"><AppCard title="自动方言"><view class="subtitle">无需手动切换，阿西会自动识别家乡话。</view><picker :range="labels" @change="changeFallback"><view class="input">低置信度兜底：{{labels[index]}}</view></picker><view class="list-item">克隆音色：{{profile?.cloneVoiceId||'系统音色'}}</view><view class="list-item">唤醒词：{{wake?.wakeWord}} / {{wake?.modelVersion}}</view><button class="btn" @click="save">保存</button></AppCard></view></template><script setup lang="ts">import{ref,onMounted}from'vue';import AppCard from'@/components/AppCard.vue';import{useDeviceStore}from'@/stores/device';import{qingxierApi}from'@/services/api';import{dialectLabels}from'@/view-models';const store=useDeviceStore(),codes=Object.keys(dialectLabels)as any[],labels=Object.values(dialectLabels),index=ref(0),profile=ref<any>(),wake=ref<any>();onMounted(async()=>{await store.load();profile.value=await qingxierApi.speechProfile(store.currentId);wake.value=await qingxierApi.wakeStatus(store.currentId);index.value=Math.max(0,codes.indexOf(profile.value.fallbackDialect));});function changeFallback(e:any){index.value=Number(e.detail.value)}async function save(){profile.value=await qingxierApi.updateSpeechProfile(store.currentId,{...profile.value,fallbackDialect:codes[index.value]});uni.showToast({title:'已保存'});}</script>
